type RequestBody struct {
	URL string `json:"url"`
}

// PreviewResponse represents the response structure containing parsed preview data
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to /preview endpoint
func FetchURLPreview(ctx echo.Context) error {
	var req RequestBody

	// Bind the JSON request body
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid request body",
		})
	}

	// Validate URL
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is OK
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Unexpected response status: " + resp.Status,
		})
	}

	// Parse HTML to extract title and meta description
	var title, description string
	z := html.NewTokenizer(resp.Body)
loop:
	for {
		tt := z.Next()

		switch {
		case tt == html.ErrorToken:
			if z.Err() == io.EOF {
				break loop
			}
			continue
		case tt == html.StartTagToken:
			t := z.Token()
			switch t.Data {
			case "title":
				// Next token should be the title content
				if z.Next() == html.TextToken {
					title = html.UnescapeString(z.Token().Data)
				}
			case "meta":
				var name, content string
				for _, attr := range t.Attr {
