					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = html.UnescapeString(content)
				}
			}
		}

		// Break early if both title and description are found
		if title != "" && description != "" {
			break loop
		}
	}

	// Return the response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
