package main

import (
	"encoding/json"
	"io"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request represents the expected JSON body with the URL to preview
type Request struct {
	URL string `json:"url"`
}

// PreviewResponse contains the extracted title and description from the URL
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL preview data
func FetchURLPreview(c echo.Context) error {
	// Parse request body
	req := new(Request)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "failed to parse request body: " + err.Error(),
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Read and parse the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to read response body: " + err.Error(),
		})
	}

	// Parse HTML to extract title and description
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to parse HTML: " + err.Error(),
		})
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		// Extract title
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
		}

		// Extract meta description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = attr.Val
				} else if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				description = content
			}
		}

		for child := n.FirstChild; child != nil; child = child.NextSibling {
			f(child)
		}
	}
	f(doc)

	// Return the preview data as JSON
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler for /preview path with POST method
	e.POST("/preview", FetchURLPreview)

	// Start server (listening on default port 8080)
	e.Logger.Fatal(e.Start(":8080"))
}

