package main

import (
	"context"
	"encoding/json"
	"io"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request struct for incoming POST request
type Request struct {
	URL string `json:"url" validate:"required,url"`
}

// Response struct for outgoing JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles POST requests to /preview
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	// Create a context with 3-second timeout for fetching the URL
	ctxTimeout, cancel := context.WithTimeout(ctx.Request().Context(), 3*time.Second)
	defer cancel()

	// Fetch the URL with timeout
	reqHTTP, err := http.NewRequestWithContext(ctxTimeout, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	client := &http.Client{}
	respHTTP, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer respHTTP.Body.Close()

	// Read response body
	body, err := io.ReadAll(respHTTP.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML to extract title and description
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// Extract page title
	title := extractTitle(doc)

	// Extract meta description
	description := extractMetaDescription(doc)

	// Prepare response
	response := Response{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	// Return JSON response
	return ctx.JSON(http.StatusOK, response)
}

// extractTitle extracts the <title> tag content from parsed HTML
func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
		return n.FirstChild.Data
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}

	return ""
}

// extractMetaDescription extracts the content of meta[name="description"] tag from parsed HTML
func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var name, content string
		for _, attr := range n.Attr {
			if attr.Key == "name" {
				name = attr.Val
			} else if attr.Key == "content" {
				content = attr.Val
			}
		}

		if name == "description" {
			return content
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := extractMetaDescription(c); desc != "" {
			return desc
		}
	}

	return ""
}

