	"golang.org/x/net/html"
)

// RequestPayload holds the URL from the request body
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload holds the preview results
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler for /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the request to fetch and parse URL content
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var reqPayload RequestPayload
	if err := ctx.Bind(&reqPayload); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	// Validate URL
	if reqPayload.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL parameter is required"})
	}

	// Create context with 3-second timeout
	timeoutCtx, cancel := context.WithTimeout(ctx.Request().Context(), 3*time.Second)
	defer cancel()

	// Create HTTP request with context
	req, err := http.NewRequestWithContext(timeoutCtx, "GET", reqPayload.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Send request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response"})
	}

	// Parse HTML to extract title and description
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Check for title tag
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Check for meta description tag
			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						nameAttr = attr.Val
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}

				if nameAttr == "description" {
					description = contentAttr
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Return JSON response
	return ctx.JSON(http.StatusOK, ResponsePayload{
		Title:       title,
		Description: description,
	})
}

