			return strings.TrimSpace(title), strings.TrimSpace(description)
		case html.StartTagToken:
			t := z.Token()
			isTitle := t.Data == "title"
			isMeta := t.Data == "meta"
			if isTitle {
				// Get title content
				if z.Next() == html.TextToken {
					title = string(z.Text())
				}
			} else if isMeta {
