	}

	// Validate URL
	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ResponseBody{Error: "URL is required"})
	}

	// Fetch URL with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ResponseBody{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check response status
