package main

import (
	"bytes"
	"io/ioutil"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request struct to parse incoming JSON body
type URLRequest struct {
	URL string `json:"url"`
}

// Response struct to return the preview data
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the request to fetch URL preview
func FetchURLPreview(ctx echo.Context) error {
	// Parse the incoming JSON body
	req := new(URLRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request"})
	}

	// Validate the URL
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Fetch the URL with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read the response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response"})
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(body)

	// Return the response
	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML parses HTML content to extract title and meta description
func parseHTML(data []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(data))
	if err != nil {
		return "", ""
	}

	var title, description string
	var parseNode func(*html.Node)
	parseNode = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = n.FirstChild.Data
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			parseNode(c)
		}
	}
	parseNode(doc)

	return title, description
}

