package main

import (
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Validate host to prevent SSRF
	host := parsedURL.Hostname()
	if isInternalHost(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Internal URLs are not allowed"})
	}

	// Fetch the URL with timeout and body size limit
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit response body size to 1MB to prevent resource exhaustion
	const maxBodySize = 1024 * 1024 // 1MB
	limitedBody := io.LimitReader(resp.Body, maxBodySize)
	body, err := io.ReadAll(limitedBody)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// isInternalHost checks if a hostname is an internal IP address or localhost
func isInternalHost(host string) bool {
	// Check for localhost variations
	if strings.EqualFold(host, "localhost") || strings.EqualFold(host, "127.0.0.1") || strings.EqualFold(host, "::1") {
		return true
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		// If resolution fails, assume it's not internal (fallback)
		return false
	}

	for _, ip := range ips {
		// Check for private IP ranges (RFC1918) and loopback
		if ip.IsLoopback() || ip.IsPrivate() {
			return true
		}
	}

	return false
}

// extractTitleAndDescription parses HTML content to find title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	// Extract title
	title := doc.Find("title").Text()
	title = strings.TrimSpace(title)

	// Extract meta description
	var description string
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		if name, exists := s.Attr("name"); exists && strings.EqualFold(name, "description") {
			if content, hasContent := s.Attr("content"); hasContent {
				description = strings.TrimSpace(content)
			}
		}
	})

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

