package main

import (
    "context"
    "io/ioutil"
    "net/http"
    "strings"
    "time"

    "github.com/PuerkitoBio/goquery"
    "github.com/labstack/echo/v4"
)

// RequestBody represents the incoming JSON body for the preview request
type RequestBody struct {
    URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response with the URL preview
type PreviewResponse struct {
    Title       string `json:"title"`
    Description string `json:"description"`
}

// FetchURLPreview handles the /preview endpoint
func FetchURLPreview(ctx echo.Context) error {
    // Bind request body to struct
    var reqBody RequestBody
    if err := ctx.Bind(&reqBody); err != nil {
        return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "Invalid request body"})
    }

    // Validate URL is present
    if reqBody.URL == "" {
        return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "URL field is required"})
    }

    // Create HTTP client with 3 second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Fetch the URL
    resp, err := client.Get(reqBody.URL)
    if err != nil {
        return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to fetch URL: " + err.Error()})
    }
    defer resp.Body.Close()

    // Read response body
    body, err := ioutil.ReadAll(resp.Body)
    if err != nil {
        return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to read response body: " + err.Error()})
    }

    // Parse HTML using goquery
    doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
    if err != nil {
        return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": "Failed to parse HTML: " + err.Error()})
    }

    // Extract page title
    title := doc.Find("title").First().Text()

    // Extract meta description
    description := ""
    doc.Find("meta").Each(func(i int, s *goquery.Selection) {
        if name, exists := s.Attr("name"); exists && name == "description" {
            description, _ = s.Attr("content")
        } else if property, exists := s.Attr("property"); exists && property == "og:description" {
            // Fallback to OpenGraph description if regular meta description not found
            description, _ = s.Attr("content")
        }
    })

    // Return the preview data as JSON
    return ctx.JSON(http.StatusOK, PreviewResponse{
        Title:       title,
        Description: description,
    })
}

func main() {
    // Initialize Echo instance
    e := echo.New()

    // Register the handler under /preview path
    e.POST("/preview", FetchURLPreview)

    // Start server on port 1323
    e.Logger.Fatal(e.Start(":1323"))
}

