import (
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF by blocking localhost, loopback, and private IP addresses
	host := parsedURL.Hostname()
	if isBlockedHost(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Blocked host"})
	}

	// Fetch the URL with security controls
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirect chain length to prevent loops
			if len(via) >= 5 {
				return http.ErrUseLastResponse
			}
			// Only allow redirects to HTTP/HTTPS URLs
			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return http.ErrUseLastResponse
			}
			// Block redirects to blocked hosts
			if isBlockedHost(req.URL.Hostname()) {
				return http.ErrUseLastResponse
			}
			return nil
		},
		Transport: &http.Transport{
			MaxIdleConns:        100,
			IdleConnTimeout:     90 * time.Second,
			MaxResponseHeaderBytes: 1024 * 1024, // 1MB limit on headers
			DisableCompression:  true,
		},
	}

	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Check Content-Type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTML content is supported"})
	}

	// Limit response body size to prevent DoS (e.g., 10MB)
	const maxBodySize = 10 * 1024 * 1024
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize+1))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}
	if len(body) > maxBodySize {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Response body too large"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func isBlockedHost(host string) bool {
	// Block localhost/loopback addresses
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return true
	}

	// Check if host is a private IP address
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
