package main

import (
	"context"
	"io"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type RequestBody struct {
	URL string `json:"url"`
}

type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var reqBody RequestBody
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	// Set a 3-second timeout for fetching the URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read and parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	// Extract title and description
	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		switch n.Type {
		case html.ElementNode:
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = n.FirstChild.Data
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	// Return the response
	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":1323"))
}

