	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch URL content
	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL: status code " + resp.Status})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// Extract title and meta description
	title, description := extractTitleAndDescription(doc)

	// Return response
	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to find title and meta description
func extractTitleAndDescription(doc *html.Node) (string, string) {
	var title, description string

	var traverse func(n *html.Node)
	traverse = func(n *html.Node) {
		// Find title
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
		}
		// Find meta description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				description = content
			}
		}
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Initialize Echo
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register handler
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

