	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// RequestBody represents the JSON request body structure
type RequestBody struct {
	URL string `json:"url"`
}

// Response represents the JSON response structure
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the URL preview request
func FetchURLPreview(ctx echo.Context) error {
	var reqBody RequestBody
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check if the response is successful
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}

	// Parse HTML content
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	// Extract title and meta description
	title := doc.Find("title").Text()
	description := doc.Find("meta[name='description']").AttrOr("content", "")

	// Return JSON response
	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Route
